import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart, ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface Route {
  routeName: string;
  estimatedTime: number;
  trafficLevel: string;
}

interface TrafficLevel {
  time: string;
  level: string;
}

interface CommuteData {
  currentRoute: Route;
  alternativeRoutes: Route[];
  trafficTrend: TrafficLevel[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const commuteData = response.data as CommuteData;
  const metaData = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#121212', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Current Route
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ color: metaData.primaryColor }}>
              {commuteData.currentRoute.routeName}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Estimated Time: {commuteData.currentRoute.estimatedTime} mins
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Traffic Level: {commuteData.currentRoute.trafficLevel}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Alternative Routes
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {commuteData.alternativeRoutes.map((route, index) => (
                <Chip
                  key={index}
                  label={`${route.routeName} (${route.estimatedTime} mins, ${route.trafficLevel})`}
                  sx={{ fontSize: '11px', bgcolor: metaData.accentColor, color: '#000' }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: commuteData.trafficTrend.map(trend => trend.level === 'Light' ? 1 : trend.level === 'Moderate' ? 2 : 3),
                  color: metaData.primaryColor,
                  label: 'Traffic Level',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: commuteData.trafficTrend.map(trend => trend.time),
                  id: 'times',
                },
              ]}
              yAxis={[{ id: 'levels', scaleType: 'linear', tickFormat: (value) => ['Light', 'Moderate', 'Heavy'][value - 1] }]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="times"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="levels"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
